266→mod tests {
267→    use super::*;
268→    use crate::protocol::{ExecuteResult, PerformanceMetrics};
269→
270→    /// Helper to build an `ExecuteResult` with a given branch path.
271→    fn make_result(branch_path: Vec<BranchDecision>) -> ExecuteResult {
272→        ExecuteResult {
273→            return_value: None,
274→            thrown_error: None,
275→            branch_path,
276→            lines_executed: vec![],
277→            calls_to_external: vec![],
278→            path_constraints: vec![],
279→            side_effects: vec![],
280→            scope_events: vec![],
281→            capture_truncation: None,
282→            performance: PerformanceMetrics {
283→                wall_time_ms: 0.0,
284→                cpu_time_us: 0,
