291→    /// Helper to build a `BranchDecision` with a numeric comparison constraint.
292→    fn numeric_branch(id: u32, taken: bool, op: BinOpKind, left: i64, right: i64) -> BranchDecision {
293→        BranchDecision {
294→            branch_id: id,
295→            line: id * 10,
