331→
332→    #[test]
333→    fn normalize_distance_large_gives_near_one() {
334→        let d = normalize_distance(1000.0);
335→        assert!(d > 0.99 && d < 1.0, "expected near 1.0, got {d}");
336→    }
337→
338→    // -----------------------------------------------------------------------
339→    // Branch distance — comparison operators
340→    // -----------------------------------------------------------------------
341→
342→    #[test]
343→    fn branch_distance_eq_exact_match() {
344→        assert_eq!(comparison_distance(BinOpKind::Eq, 5.0, 5.0), 0.0);
