383→
384→    // -----------------------------------------------------------------------
385→    // Coverage score
386→    // -----------------------------------------------------------------------
387→
388→    #[test]
389→    fn empty_execution_coverage_zero() {
390→        assert_eq!(coverage_score(&[], 5), 0.0);
391→    }
392→
393→    #[test]
394→    fn coverage_no_targets_is_perfect() {
395→        assert_eq!(coverage_score(&[], 0), 1.0);
