413→
414→    // -----------------------------------------------------------------------
415→    // Novelty
416→    // -----------------------------------------------------------------------
417→
418→    #[test]
419→    fn novelty_new_path_scores_one() {
420→        let mut ctx = FitnessContext::new();
421→        let path = vec![numeric_branch(1, true, BinOpKind::Gt, 10, 5)];
422→        assert_eq!(novelty_score(&path, &mut ctx), 1.0);
