441→        let mut ctx = FitnessContext::new();
442→        let breakdown = score(&result, &targets, &mut ctx, &FitnessWeights::default());
443→
444→        assert_eq!(breakdown.coverage, 0.0);
445→        assert_eq!(breakdown.proximity, 0.0);
446→        assert_eq!(breakdown.unknown_bonus, 0.0);
447→        // novelty is 1.0 because even an empty path is "new" the first time
448→        assert!(breakdown.total < 0.3, "expected low total, got {}", breakdown.total);
