451→    #[test]
452→    fn all_targets_hit_scores_high() {
453→        let path = vec![
454→            numeric_branch(1, true, BinOpKind::Eq, 5, 5),
455→            numeric_branch(2, true, BinOpKind::Eq, 10, 10),
456→        ];
457→        let result = make_result(path);
458→        let targets: HashSet<u32> = [1, 2].into_iter().collect();
459→        let mut ctx = FitnessContext::new();
