467→    #[test]
468→    fn custom_weights_affect_total() {
469→        let path = vec![numeric_branch(1, true, BinOpKind::Eq, 5, 5)];
470→        let result = make_result(path);
471→        let targets: HashSet<u32> = [1].into_iter().collect();
472→        let mut ctx = FitnessContext::new();
473→
474→        // Only proximity weight
475→        let weights = FitnessWeights {
476→            coverage: 0.0,
477→            proximity: 1.0,
478→            unknown_bonus: 0.0,
479→            novelty: 0.0,
480→        };
481→        let breakdown = score(&result, &targets, &mut ctx, &weights);
482→        assert_eq!(breakdown.total, breakdown.proximity);
483→    }
