485→    #[test]
486→    fn default_weights_sum_to_one() {
487→        let w = FitnessWeights::default();
488→        let sum = w.coverage + w.proximity + w.unknown_bonus + w.novelty;
489→        assert!((sum - 1.0).abs() < f64::EPSILON, "weights sum to {sum}, expected 1.0");
490→    }
