492→    #[test]
493→    fn fitness_always_in_zero_one_range() {
494→        let scenarios: Vec<Vec<BranchDecision>> = vec![
495→            vec![],
496→            vec![numeric_branch(1, true, BinOpKind::Gt, 100, 0)],
497→            vec![unknown_branch(1), unknown_branch(2), unknown_branch(3)],
498→            vec![
499→                numeric_branch(1, false, BinOpKind::Lt, 50, 10),
500→                numeric_branch(2, true, BinOpKind::Eq, 7, 7),
501→                unknown_branch(3),
502→            ],
503→        ];
504→        let targets: HashSet<u32> = [1, 2, 3, 4].into_iter().collect();
505→
506→        for (i, path) in scenarios.into_iter().enumerate() {
507→            let mut ctx = FitnessContext::new();
508→            let result = make_result(path);
509→            let b = score(&result, &targets, &mut ctx, &FitnessWeights::default());
510→            assert!(
511→                b.total >= 0.0 && b.total <= 1.0,
512→                "scenario {i}: total {:.4} out of range",
513→                b.total
514→            );
515→            assert!(b.coverage >= 0.0 && b.coverage <= 1.0);
516→            assert!(b.proximity >= 0.0 && b.proximity <= 1.0);
517→            assert!(b.unknown_bonus >= 0.0 && b.unknown_bonus <= 1.0);
518→            assert!(b.novelty >= 0.0 && b.novelty <= 1.0);
519→        }
520→    }
521→
522→    #[test]
523→    fn zero_weights_give_zero_total() {
524→        let result = make_result(vec![numeric_branch(1, true, BinOpKind::Eq, 5, 5)]);
525→        let targets: HashSet<u32> = [1].into_iter().collect();
526→        let mut ctx = FitnessContext::new();
527→        let weights = FitnessWeights {
528→            coverage: 0.0,
529→            proximity: 0.0,
530→            unknown_bonus: 0.0,
531→            novelty: 0.0,
532→        };
533→        let b = score(&result, &targets, &mut ctx, &weights);
534→        assert_eq!(b.total, 0.0);
535→    }
536→}
